## Summary

- Stop defaulting Claude CLI runs to `--permission-mode bypassPermissions`; OpenClaw now only requests that mode when the explicit exec policy is full access with asks disabled.
- Align the live `claude-stdio` launch path with the Anthropic backend normalization path: default and restrictive policies leave Claude permission mode unset, and raw backend `--permission-mode` args are stripped unless explicit OpenClaw YOLO policy enables bypass.
- Preserve upstream Claude CLI safety defaults from `main`, including `--allowedTools mcp__openclaw__*`, `--setting-sources user`, native compaction ownership, and always-on resumed system prompt behavior.

## Verification

Commands run:
- `CI=true pnpm install --frozen-lockfile`
- `pnpm test:extension anthropic`
- `node scripts/run-vitest.mjs run --config test/vitest/vitest.agents-core.config.ts`
- `node scripts/run-vitest.mjs run --config test/vitest/vitest.agents-support.config.ts`
- `node scripts/run-vitest.mjs run src/agents/cli-backends.test.ts src/agents/cli-runner.spawn.test.ts src/agents/cli-runner/helpers.system-prompt-resume.test.ts`
- `node scripts/run-vitest.mjs run --config test/vitest/vitest.commands.config.ts src/commands/agent-via-gateway.test.ts`
- `pnpm check`
- `pnpm build`
- `pnpm test` (latest full run passed all 88 Vitest shards in 676.46s)

## Real behavior proof

- Behavior or issue addressed: Claude live-session argv generation no longer injects `--permission-mode bypassPermissions` by default, and raw backend `--permission-mode` values cannot leak through the live path without an explicit OpenClaw YOLO exec policy.
- Real environment tested: Local OpenClaw source checkout at PR head `f9ec0af38f9dc0561f4a7b8f842f428f4e2c5cec`.
- Exact steps or command run after this patch:

```sh
node --import tsx --input-type=module -e '
import { runClaudeLiveSessionTurn, resetClaudeLiveSessionsForTest } from "./src/agents/cli-runner/claude-live-session.ts";

const makeContext = (name, backendArgs, config) => ({
  params: {
    sessionId: `proof-${name}`,
    sessionKey: `main:proof-${name}`,
    sessionFile: `/tmp/proof-${name}.jsonl`,
    workspaceDir: "/tmp",
    config,
    prompt: "hello",
    provider: "claude-cli",
    model: "sonnet",
    runId: `run-${name}`,
  },
  started: Date.now(),
  workspaceDir: "/tmp",
  backendResolved: {
    id: "claude-cli",
    config: {
      command: "claude",
      args: backendArgs,
      output: "jsonl",
      input: "stdin",
      modelArg: "--model",
      sessionArg: "--session-id",
      sessionMode: "always",
      systemPromptFileArg: "--append-system-prompt-file",
      systemPromptWhen: "first",
      liveSession: "claude-stdio",
      serialize: true,
    },
    bundleMcp: true,
    pluginId: "anthropic",
  },
  preparedBackend: {
    backend: {
      command: "claude",
      args: backendArgs,
      output: "jsonl",
      input: "stdin",
      modelArg: "--model",
      sessionArg: "--session-id",
      sessionMode: "always",
      systemPromptFileArg: "--append-system-prompt-file",
      systemPromptWhen: "first",
      liveSession: "claude-stdio",
      serialize: true,
    },
    env: {},
  },
  reusableCliSession: {},
  hadSessionFile: false,
  contextEngineConfig: {},
  modelId: "sonnet",
  normalizedModel: "sonnet",
  systemPrompt: "You are a helpful assistant.",
  systemPromptReport: {},
  bootstrapPromptWarningLines: [],
  authEpochVersion: 2,
});

async function runCase(name, backendArgs, config) {
  resetClaudeLiveSessionsForTest();
  let onStdout;
  let captured;
  const stdin = {
    write(data, cb) {
      onStdout?.(`${JSON.stringify({ type: "system", subtype: "init", session_id: `sid-${name}` })}\n${JSON.stringify({ type: "result", session_id: `sid-${name}`, result: "ok" })}\n`);
      cb?.();
    },
    end() {},
  };
  const supervisor = {
    spawn: async (input) => {
      captured = input;
      onStdout = input.onStdout;
      return {
        runId: `managed-${name}`,
        pid: 4400,
        startedAtMs: Date.now(),
        stdin,
        wait: async () => new Promise(() => {}),
        cancel() {},
      };
    },
  };
  await runClaudeLiveSessionTurn({
    context: makeContext(name, backendArgs, config),
    args: backendArgs,
    env: {},
    prompt: "hello",
    useResume: false,
    getProcessSupervisor: () => supervisor,
    noOutputTimeoutMs: 1000,
    onAssistantDelta: () => {},
    cleanup: async () => {},
  });
  const argv = captured?.argv ?? [];
  const idx = argv.indexOf("--permission-mode");
  console.log(`${name}: permissionMode=${idx >= 0 ? argv[idx + 1] : "<omitted>"}`);
  console.log(`${name}: argv=${JSON.stringify(argv)}`);
}

await runCase("default-no-config", ["-p", "--output-format", "stream-json"], undefined);
await runCase("raw-bypass-no-config", ["-p", "--output-format", "stream-json", "--permission-mode", "bypassPermissions"], undefined);
await runCase("explicit-yolo", ["-p", "--output-format", "stream-json", "--permission-mode", "default"], { tools: { exec: { security: "full", ask: "off" } } });
resetClaudeLiveSessionsForTest();
'
```

- Evidence after fix (copied terminal output):

```text
default-no-config: permissionMode=<omitted>
default-no-config: argv=["claude","-p","--input-format","stream-json","--output-format","stream-json","--permission-prompt-tool","stdio","--replay-user-messages"]
raw-bypass-no-config: permissionMode=<omitted>
raw-bypass-no-config: argv=["claude","-p","--input-format","stream-json","--output-format","stream-json","--permission-prompt-tool","stdio","--replay-user-messages"]
explicit-yolo: permissionMode=bypassPermissions
explicit-yolo: argv=["claude","-p","--input-format","stream-json","--output-format","stream-json","--permission-prompt-tool","stdio","--replay-user-messages","--permission-mode","bypassPermissions"]
```

- Observed result after fix: The actual Claude live-session launch path omits Claude `--permission-mode` for missing config, strips a raw `--permission-mode bypassPermissions` backend arg when no explicit exec policy exists, and adds `--permission-mode bypassPermissions` only for explicit `tools.exec.security: "full"` with `tools.exec.ask: "off"`.
- What was not tested: A live Claude model/API request was not sent from this machine. The proof covers OpenClaw's real Claude live-session spawn path with a fake process supervisor so no external Claude process or secret is required.
- Proof limitations or environment constraints: The command is local terminal output from the OpenClaw source checkout and redacts no secrets because none were printed.
